import { createContext, useContext, useState, useEffect } from 'react';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface NotificationContextValue {
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextValue | null>(null);

const useNotificationContext = () => {
  const [notificationElem, setNotificationElem] = useState<HTMLElement | null>(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElem(element);
    }
  }, []);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  return { notify, notificationElem };
};

export default useNotificationContext;
